#!/usr/bin/env python3
"""Find all classes in litellm/llms that inherit from BaseConfig (directly or indirectly)."""
import ast
import os
import sys
from collections import defaultdict
from pathlib import Path

REPO_ROOT = Path("/Users/luc/Developer/luuuc/oss/sense-benchmark/baseline/litellm")
LLMS_ROOT = REPO_ROOT / "litellm" / "llms"


def module_from_path(path: Path) -> str:
    rel = path.relative_to(REPO_ROOT / "litellm")
    parts = rel.with_suffix("").parts
    return "litellm." + ".".join(parts)


def resolve_relative_import(level: int, module: str, current_module: str) -> str:
    cur_parts = current_module.split(".")
    # relative imports are relative to current package, drop `level` parts from end
    base_parts = cur_parts[:-level] if level <= len(cur_parts) else []
    if module:
        return ".".join(base_parts + module.split("."))
    return ".".join(base_parts)


def parse_file(path: Path):
    try:
        tree = ast.parse(path.read_text(encoding="utf-8"), filename=str(path))
    except Exception as e:
        print(f"WARN: cannot parse {path}: {e}", file=sys.stderr)
        return None
    module = module_from_path(path)
    imports = {}  # name -> fully qualified module or module.object
    classes = []  # list of dicts: name, bases [str], lineno
    for node in ast.walk(tree):
        if isinstance(node, ast.Import):
            for alias in node.names:
                mod = alias.name
                asname = alias.asname or mod.split(".")[-1]
                imports[asname] = {"type": "module", "module": mod}
        elif isinstance(node, ast.ImportFrom):
            if node.module is None:
                mod = resolve_relative_import(node.level, "", module)
            else:
                mod = resolve_relative_import(node.level, node.module, module)
            for alias in node.names:
                name = alias.name
                asname = alias.asname or name
                imports[asname] = {"type": "name", "module": mod, "name": name}
        elif isinstance(node, ast.ClassDef):
            bases = []
            for base in node.bases:
                if isinstance(base, ast.Name):
                    bases.append(base.id)
                elif isinstance(base, ast.Attribute):
                    # e.g. module.ClassName
                    bases.append(ast.unparse(base))
                else:
                    bases.append(ast.unparse(base))
            classes.append({
                "name": node.name,
                "bases": bases,
                "lineno": node.lineno,
            })
    return {"module": module, "path": path, "imports": imports, "classes": classes}


def main():
    files = []
    for path in LLMS_ROOT.rglob("*.py"):
        res = parse_file(path)
        if res:
            files.append(res)

    # Build lookup for classes by (module, class)
    class_nodes = {}
    for f in files:
        for c in f["classes"]:
            key = (f["module"], c["name"])
            class_nodes[key] = {**c, "module": f["module"], "path": f["path"]}

    # Resolve base names to keys
    def resolve_base(import_map, base_str, current_module):
        # direct attribute like OpenAIGPTConfig -> lookup import map
        if "." in base_str:
            # e.g. module.ClassName or module.sub.ClassName
            parts = base_str.split(".")
            # try first part as import alias
            first = parts[0]
            if first in import_map:
                info = import_map[first]
                if info["type"] == "module":
                    mod = info["module"]
                    return (mod, parts[-1])
                else:
                    # imported name as module prefix? not typical
                    mod = info["module"]
                    return (mod, parts[-1])
            else:
                # treat as absolute module path
                return (".".join(parts[:-1]), parts[-1])
        else:
            if base_str in import_map:
                info = import_map[base_str]
                if info["type"] == "name":
                    return (info["module"], info["name"])
                else:
                    return (info["module"], base_str)
            # not imported: could be local class in same module
            return (current_module, base_str)

    edges = defaultdict(list)
    for f in files:
        imports = f["imports"]
        mod = f["module"]
        for c in f["classes"]:
            child_key = (mod, c["name"])
            for base in c["bases"]:
                parent_key = resolve_base(imports, base, mod)
                if parent_key in class_nodes:
                    edges[child_key].append(parent_key)

    # BaseConfig target
    base_key = ("litellm.llms.base_llm.chat.transformation", "BaseConfig")
    if base_key not in class_nodes:
        print(f"BaseConfig not found at expected location! {base_key}", file=sys.stderr)
        sys.exit(1)

    # BFS from base to find descendants
    descendants = set()
    stack = [base_key]
    while stack:
        node = stack.pop()
        for child, parents in edges.items():
            if node in parents and child not in descendants:
                descendants.add(child)
                stack.append(child)

    # Output descendants sorted by path, line
    results = []
    for key in sorted(descendants, key=lambda k: (class_nodes[k]["path"], class_nodes[k]["lineno"])):
        info = class_nodes[key]
        results.append({
            "module": key[0],
            "class": key[1],
            "path": str(info["path"]),
            "lineno": info["lineno"],
        })
    for r in results:
        print(f"{r['path']}:{r['lineno']} {r['class']}")
    print(f"\nTotal classes inheriting BaseConfig: {len(results)}", file=sys.stderr)


if __name__ == "__main__":
    main()

