                "name": node.name,
                "bases": bases,
                "lineno": node.lineno,
            })
    return {"module": module, "path": path, "imports": imports, "classes": classes}


def main():
    files = []
    for path in LLMS_ROOT.rglob("*.py"):
        res = parse_file(path)
        if res:
            files.append(res)

    class_nodes = {}
    for f in files:
        for c in f["classes"]:
            key = (f["module"], c["name"])
            class_nodes[key] = {**c, "module": f["module"], "path": f["path"]}

    def resolve_base(import_map, base_str, current_module):
        if "." in base_str:
            parts = base_str.split(".")
            first = parts[0]
            if first in import_map:
                info = import_map[first]
                if info["type"] == "module":
                    mod = info["module"]
                    return (mod, parts[-1])
                else:
                    mod = info["module"]
                    return (mod, parts[-1])
            else:
                return (".".join(parts[:-1]), parts[-1])
        else:
            if base_str in import_map:
                info = import_map[base_str]
                if info["type"] == "name":
                    return (info["module"], info["name"])
                else:
                    return (info["module"], base_str)
            return (current_module, base_str)

    edges = defaultdict(list)
    for f in files:
        imports = f["imports"]
        mod = f["module"]
        for c in f["classes"]:
            child_key = (mod, c["name"])
            for base in c["bases"]:
                parent_key = resolve_base(imports, base, mod)
                if parent_key in class_nodes:
                    edges[child_key].append(parent_key)

    base_key = ("litellm.llms.base_llm.chat.transformation", "BaseConfig")

    # Compute descendants via BFS over parent->child map
    parent_to_children = defaultdict(list)
    for child, parents in edges.items():
        for p in parents:
            parent_to_children[p].append(child)

    descendants = set()
    stack = [base_key]
    while stack:
        node = stack.pop()
        for child in parent_to_children[node]:
            if child not in descendants:
                descendants.add(child)
                stack.append(child)

    # Compute parent chain for each descendant
    def parent_chain(child):
        chain = []
        seen = set()
        cur = child
        while True:
            parents = edges.get(cur, [])
            # pick a parent that is in descendants or base_key
            next_parent = None
            for p in parents:
                if p == base_key or p in descendants:
                    next_parent = p
                    break
            if next_parent is None or next_parent in seen:
                break
            seen.add(next_parent)
            chain.append(next_parent)
            cur = next_parent
            if cur == base_key:
                break
        return list(reversed(chain))

    # chat classification heuristics
    def is_chat_path(path: Path) -> bool:
        s = str(path)
        if "/chat/" in s or s.endswith("/chat.py"):
            return True
        # special chat-only provider files
        if s.endswith("/openai/openai.py") or s.endswith("/maritalk.py"):
            return True
        return False

    def overrides_notimplemented(child_key):
        info = class_nodes[child_key]
        path = info["path"]
        try:
            tree = ast.parse(path.read_text(encoding="utf-8"), filename=str(path))
        except Exception:
            return False
        for node in ast.walk(tree):
            if isinstance(node, ast.ClassDef) and node.name == info["name"]:
                for item in node.body:
                    if isinstance(item, ast.FunctionDef) and item.name in ("transform_request", "transform_response"):
                        body_text = ast.unparse(item.body)
                        if "NotImplementedError" in body_text:
                            return True
        return False

    def is_chat(child_key, chain):
        # if path is chat dir or file, yes
        if is_chat_path(class_nodes[child_key]["path"]):
            return True
        # if any parent path is chat dir and this class does not override transform_request to NotImplementedError
        # heuristic: if it overrides transform_request with NotImplementedError, it's a non-chat reusing a chat parent
        if overrides_notimplemented(child_key):
            return False
        return False

    # Print all descendants with chain
    rows = []
    for key in sorted(descendants, key=lambda k: (class_nodes[k]["path"], class_nodes[k]["lineno"])):
        chain = parent_chain(key)
        chain_names = [f"{p[1]} ({class_nodes[p]['module']})" for p in chain]
        chat = is_chat(key, chain)
        rows.append({
            "path": str(class_nodes[key]["path"]),
            "lineno": class_nodes[key]["lineno"],
            "class": key[1],
            "chat": chat,
            "chain": " -> ".join(chain_names + [key[1]]),
        })

    # Print CSV-like
    print("chat|path|line|class|chain")
    for r in rows:
        print(f"{r['chat']}|{r['path']}|{r['lineno']}|{r['class']}|{r['chain']}")


if __name__ == "__main__":
    main()

